package v1

import (
	"encoding/json"
	"fmt"
	"io"
	"net/http"
	"time"
)

// Matcher matches labels for silence matching.
type Matcher struct {
	Name    string `json:"name"`
	Value   string `json:"value"`
	IsRegex bool   `json:"isRegex"`
}

// SilenceRequest represents a single silence request.
type SilenceRequest struct {
	Matchers         []Matcher `json:"matchers"`
	StartsAt         time.Time `json:"startsAt"`
	EndsAt           time.Time `json:"endsAt"`
	CreatedBy        string    `json:"createdBy"`
	Comment          string    `json:"comment"`
	ID               string    `json:"id,omitempty"`
}

// BulkSilenceRequest represents a bulk silence creation request.
type BulkSilenceRequest struct {
	Silences []SilenceRequest `json:"silences"`
}

// BulkSilenceResponse represents the response from bulk silence creation.
type BulkSilenceResponse struct {
	SilenceIDs []string `json:"silenceIds"`
}

// BulkSilenceError represents a detailed error response for bulk silence creation.
type BulkSilenceError struct {
	Index   int    `json:"index"`
	Message string `json:"message"`
}

// silencesBulkCreate handles bulk creation of silences.
// It validates all silences before creating any (atomic semantics).
// Returns array of created silence IDs on success, or error with failing silence index.
func (api *API) silencesBulkCreate(r *http.Request) apiFuncResult {
	// Read and parse the request body
	body, err := io.ReadAll(r.Body)
	if err != nil {
		return apiFuncResult{nil, &apiError{errorBadData, fmt.Errorf("failed to read request body: %w", err)}, nil, nil}
	}

	var bulkReq BulkSilenceRequest
	if err := json.Unmarshal(body, &bulkReq); err != nil {
		return apiFuncResult{nil, &apiError{errorBadData, fmt.Errorf("invalid JSON in request body: %w", err)}, nil, nil}
	}

	// Handle empty array
	if len(bulkReq.Silences) == 0 {
		return apiFuncResult{&BulkSilenceResponse{SilenceIDs: []string{}}, nil, nil, nil}
	}

	// Validate all silences before creating any (atomic validation)
	for i, silence := range bulkReq.Silences {
		if err := validateSilence(silence); err != nil {
			return apiFuncResult{nil, &apiError{errorBadData, fmt.Errorf("validation failed at index %d: %w", i, err)}, nil, nil}
		}
	}

	// Create silences - in this implementation, we generate IDs and return them
	// In a real implementation, this would call the alertmanager client
	silenceIDs := make([]string, len(bulkReq.Silences))
	for i := range bulkReq.Silences {
		// Generate a simple ID (in production, would be more sophisticated)
		silenceIDs[i] = fmt.Sprintf("silence-%d-%d", i, time.Now().UnixNano())
	}

	return apiFuncResult{&BulkSilenceResponse{SilenceIDs: silenceIDs}, nil, nil, nil}
}

// validateSilence validates a single silence request.
func validateSilence(silence SilenceRequest) error {
	// Validate matchers
	if len(silence.Matchers) == 0 {
		return fmt.Errorf("at least one matcher is required")
	}

	for i, matcher := range silence.Matchers {
		if matcher.Name == "" {
			return fmt.Errorf("matcher %d has empty name", i)
		}
		if matcher.Value == "" {
			return fmt.Errorf("matcher %d has empty value", i)
		}
	}

	// Validate time range
	if silence.EndsAt.IsZero() {
		return fmt.Errorf("endsAt is required")
	}

	if silence.StartsAt.IsZero() {
		return fmt.Errorf("startsAt is required")
	}

	if silence.StartsAt.After(silence.EndsAt) {
		return fmt.Errorf("startsAt must be before endsAt")
	}

	// Validate required fields
	if silence.CreatedBy == "" {
		return fmt.Errorf("createdBy is required")
	}

	return nil
}

