func TestSilencesBulkCreate(t *testing.T) {
	api := &API{
		ready: func(f http.HandlerFunc) http.HandlerFunc { return f },
	}

	router := route.New()
	router.Post("/api/v1/silences/bulk", func(f http.HandlerFunc) http.HandlerFunc {
		return f
	}(api.silencesBulkCreate))

	tests := []struct {
		name           string
		request        *BulkSilenceRequest
		expectStatus   int
		expectError    bool
		expectIDs      int
		errorMessage   string
	}{
		{
			name: "successful bulk creation",
			request: &BulkSilenceRequest{
				Silences: []SilenceRequest{
					{
						Matchers: []Matcher{
							{Name: "alertname", Value: "TestAlert", IsRegex: false},
						},
						StartsAt:  time.Now(),
						EndsAt:    time.Now().Add(1 * time.Hour),
						CreatedBy: "test-user",
						Comment:   "Test silence",
					},
					{
						Matchers: []Matcher{
							{Name: "job", Value: "test-job", IsRegex: false},
						},
						StartsAt:  time.Now(),
						EndsAt:    time.Now().Add(2 * time.Hour),
						CreatedBy: "test-user",
						Comment:   "Another silence",
					},
				},
			},
			expectStatus: http.StatusOK,
			expectError:  false,
			expectIDs:    2,
		},
		{
			name: "empty silence array",
			request: &BulkSilenceRequest{
				Silences: []SilenceRequest{},
			},
			expectStatus: http.StatusOK,
			expectError:  false,
			expectIDs:    0,
		},
		{
			name: "validation failure - missing matchers",
			request: &BulkSilenceRequest{
				Silences: []SilenceRequest{
					{
						Matchers:  []Matcher{},
						StartsAt:  time.Now(),
						EndsAt:    time.Now().Add(1 * time.Hour),
						CreatedBy: "test-user",
						Comment:   "Test silence",
					},
				},
			},
			expectStatus: http.StatusBadRequest,
			expectError:  true,
			errorMessage: "at least one matcher is required",
		},
		{
			name: "validation failure - empty matcher name",
			request: &BulkSilenceRequest{
				Silences: []SilenceRequest{
					{
						Matchers: []Matcher{
							{Name: "", Value: "value", IsRegex: false},
						},
						StartsAt:  time.Now(),
						EndsAt:    time.Now().Add(1 * time.Hour),
						CreatedBy: "test-user",
						Comment:   "Test silence",
					},
				},
			},
			expectStatus: http.StatusBadRequest,
			expectError:  true,
			errorMessage: "matcher 0 has empty name",
		},
		{
			name: "validation failure - empty matcher value",
			request: &BulkSilenceRequest{
				Silences: []SilenceRequest{
					{
						Matchers: []Matcher{
							{Name: "alertname", Value: "", IsRegex: false},
						},
						StartsAt:  time.Now(),
						EndsAt:    time.Now().Add(1 * time.Hour),
						CreatedBy: "test-user",
						Comment:   "Test silence",
					},
				},
			},
			expectStatus: http.StatusBadRequest,
			expectError:  true,
			errorMessage: "matcher 0 has empty value",
		},
		{
			name: "validation failure - missing createdBy",
			request: &BulkSilenceRequest{
				Silences: []SilenceRequest{
					{
						Matchers: []Matcher{
							{Name: "alertname", Value: "TestAlert", IsRegex: false},
						},
						StartsAt: time.Now(),
						EndsAt:   time.Now().Add(1 * time.Hour),
						Comment:  "Test silence",
					},
				},
			},
			expectStatus: http.StatusBadRequest,
			expectError:  true,
			errorMessage: "createdBy is required",
		},
		{
			name: "validation failure - startsAt after endsAt",
			request: &BulkSilenceRequest{
				Silences: []SilenceRequest{
					{
						Matchers: []Matcher{
							{Name: "alertname", Value: "TestAlert", IsRegex: false},
						},
						StartsAt:  time.Now().Add(2 * time.Hour),
						EndsAt:    time.Now().Add(1 * time.Hour),
						CreatedBy: "test-user",
						Comment:   "Test silence",
					},
				},
			},
			expectStatus: http.StatusBadRequest,
			expectError:  true,
			errorMessage: "startsAt must be before endsAt",
		},
		{
			name: "validation failure in second silence",
			request: &BulkSilenceRequest{
				Silences: []SilenceRequest{
					{
						Matchers: []Matcher{
							{Name: "alertname", Value: "TestAlert", IsRegex: false},
						},
						StartsAt:  time.Now(),
						EndsAt:    time.Now().Add(1 * time.Hour),
						CreatedBy: "test-user",
						Comment:   "Valid silence",
					},
					{
						Matchers:  []Matcher{},
						StartsAt:  time.Now(),
						EndsAt:    time.Now().Add(1 * time.Hour),
						CreatedBy: "test-user",
						Comment:   "Invalid silence",
					},
				},
			},
			expectStatus: http.StatusBadRequest,
			expectError:  true,
			errorMessage: "validation failed at index 1",
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			body, err := json.Marshal(tt.request)
			require.NoError(t, err)

			req := httptest.NewRequest("POST", "/api/v1/silences/bulk", bytes.NewReader(body))
			w := httptest.NewRecorder()

			api.silencesBulkCreate(req)

			// Since we're testing the handler directly, we need to test via apiFuncResult
			result := api.silencesBulkCreate(req)

			if tt.expectError {
				require.NotNil(t, result.err, "expected error but got none")
				require.Contains(t, result.err.Error(), tt.errorMessage)
			} else {
				require.Nil(t, result.err)
				resp, ok := result.data.(*BulkSilenceResponse)
				require.True(t, ok, "expected BulkSilenceResponse")
				require.Equal(t, tt.expectIDs, len(resp.SilenceIDs))
			}
		})
	}
}

func TestSilencesBulkCreateIntegration(t *testing.T) {
	// Integration test that tests the full HTTP path
	api := &API{
		ready: func(f http.HandlerFunc) http.HandlerFunc { return f },
	}

	router := route.New()
	wrap := func(f apiFunc) http.HandlerFunc {
		return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
			result := f(r)
			if result.err != nil {
				w.WriteHeader(http.StatusBadRequest)
				resp := Response{
					Status:    statusError,
					ErrorType: string(result.err.typ.num),
					Error:     result.err.Error(),
				}
				json.NewEncoder(w).Encode(resp)
				return
			}

			w.Header().Set("Content-Type", "application/json")
			json.NewEncoder(w).Encode(Response{
				Status: statusSuccess,
				Data:   result.data,
			})
		})
	}

	router.Post("/silences/bulk", wrap(api.silencesBulkCreate))

	t.Run("successful bulk creation via HTTP", func(t *testing.T) {
		req := &BulkSilenceRequest{
			Silences: []SilenceRequest{
				{
					Matchers: []Matcher{
						{Name: "alertname", Value: "TestAlert", IsRegex: false},
					},
					StartsAt:  time.Now(),
					EndsAt:    time.Now().Add(1 * time.Hour),
					CreatedBy: "test-user",
					Comment:   "Test silence",
				},
			},
		}

		body, _ := json.Marshal(req)
		httpReq := httptest.NewRequest("POST", "/silences/bulk", bytes.NewReader(body))
		httpReq.Header.Set("Content-Type", "application/json")

		w := httptest.NewRecorder()
		router.ServeHTTP(w, httpReq)

		require.Equal(t, http.StatusOK, w.Code)

		var resp Response
		json.NewDecoder(w.Body).Decode(&resp)
		require.Equal(t, string(statusSuccess), resp.Status)

		respData, ok := resp.Data.(map[string]interface{})
		require.True(t, ok)
		silenceIDs, ok := respData["silenceIds"].([]interface{})
		require.True(t, ok)
		require.Equal(t, 1, len(silenceIDs))
	})

	t.Run("validation failure via HTTP", func(t *testing.T) {
		req := &BulkSilenceRequest{
			Silences: []SilenceRequest{
				{
					Matchers:  []Matcher{},
					StartsAt:  time.Now(),
					EndsAt:    time.Now().Add(1 * time.Hour),
					CreatedBy: "test-user",
					Comment:   "Invalid silence",
				},
			},
		}

		body, _ := json.Marshal(req)
		httpReq := httptest.NewRequest("POST", "/silences/bulk", bytes.NewReader(body))
		httpReq.Header.Set("Content-Type", "application/json")

		w := httptest.NewRecorder()
		router.ServeHTTP(w, httpReq)

		require.Equal(t, http.StatusBadRequest, w.Code)

		var resp Response
		json.NewDecoder(w.Body).Decode(&resp)
		require.Equal(t, string(statusError), resp.Status)
		require.Contains(t, resp.Error, "at least one matcher is required")
	})
}

func TestValidateSilence(t *testing.T) {
	tests := []struct {
		name        string
		silence     SilenceRequest
		shouldError bool
		errorMsg    string
	}{
		{
			name: "valid silence",
			silence: SilenceRequest{
				Matchers: []Matcher{
					{Name: "alertname", Value: "TestAlert", IsRegex: false},
				},
				StartsAt:  time.Now(),
				EndsAt:    time.Now().Add(1 * time.Hour),
				CreatedBy: "test-user",
				Comment:   "Test",
			},
			shouldError: false,
		},
		{
			name: "no matchers",
			silence: SilenceRequest{
				Matchers:  []Matcher{},
				StartsAt:  time.Now(),
				EndsAt:    time.Now().Add(1 * time.Hour),
				CreatedBy: "test-user",
				Comment:   "Test",
			},
			shouldError: true,
			errorMsg:    "at least one matcher is required",
		},
		{
			name: "empty matcher name",
			silence: SilenceRequest{
				Matchers: []Matcher{
					{Name: "", Value: "value", IsRegex: false},
				},
				StartsAt:  time.Now(),
				EndsAt:    time.Now().Add(1 * time.Hour),
				CreatedBy: "test-user",
				Comment:   "Test",
			},
			shouldError: true,
			errorMsg:    "matcher 0 has empty name",
		},
		{
			name: "empty matcher value",
			silence: SilenceRequest{
				Matchers: []Matcher{
					{Name: "alertname", Value: "", IsRegex: false},
				},
				StartsAt:  time.Now(),
				EndsAt:    time.Now().Add(1 * time.Hour),
				CreatedBy: "test-user",
				Comment:   "Test",
			},
			shouldError: true,
			errorMsg:    "matcher 0 has empty value",
		},
		{
			name: "zero endsAt",
			silence: SilenceRequest{
				Matchers: []Matcher{
					{Name: "alertname", Value: "TestAlert", IsRegex: false},
				},
				StartsAt:  time.Now(),
				EndsAt:    time.Time{},
				CreatedBy: "test-user",
				Comment:   "Test",
			},
			shouldError: true,
			errorMsg:    "endsAt is required",
		},
		{
			name: "zero startsAt",
			silence: SilenceRequest{
				Matchers: []Matcher{
					{Name: "alertname", Value: "TestAlert", IsRegex: false},
				},
				StartsAt:  time.Time{},
				EndsAt:    time.Now().Add(1 * time.Hour),
				CreatedBy: "test-user",
				Comment:   "Test",
			},
			shouldError: true,
			errorMsg:    "startsAt is required",
		},
		{
			name: "startsAt after endsAt",
			silence: SilenceRequest{
				Matchers: []Matcher{
					{Name: "alertname", Value: "TestAlert", IsRegex: false},
				},
				StartsAt:  time.Now().Add(2 * time.Hour),
				EndsAt:    time.Now().Add(1 * time.Hour),
				CreatedBy: "test-user",
				Comment:   "Test",
			},
			shouldError: true,
			errorMsg:    "startsAt must be before endsAt",
		},
		{
			name: "empty createdBy",
			silence: SilenceRequest{
				Matchers: []Matcher{
					{Name: "alertname", Value: "TestAlert", IsRegex: false},
				},
				StartsAt:  time.Now(),
				EndsAt:    time.Now().Add(1 * time.Hour),
				CreatedBy: "",
				Comment:   "Test",
			},
			shouldError: true,
			errorMsg:    "createdBy is required",
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			err := validateSilence(tt.silence)
			if tt.shouldError {
				require.Error(t, err)
				require.Contains(t, err.Error(), tt.errorMsg)
			} else {
				require.NoError(t, err)
			}
		})
	}
}
